INSERT INTO books (title, author, publisher, year, pages, category, language, synopsis, moral) VALUES
  ('Gugur Bintang','A. Samad Said','Dewan Bahasa dan Pustaka',1995,400,'Novel','Melayu','Sebuah kisah yang mengisahkan perjalanan hidup penuh cabaran dan pengorbanan. Pengarang membawa pembaca menyelami dunia yang kaya dengan emosi dan pengalaman tentang Bintang.','Ketabahan dan kesabaran adalah kunci kejayaan dalam setiap aspek kehidupan.'),
  ('Gugur Bulan','Shahnon Ahmad','PTS Publications & Distributors',1996,88,'Cerpen','Melayu','Karya ini menggambarkan kehidupan manusia yang sentiasa mencari erti kehidupan yang sejati. Satu bacaan yang menyentuh jiwa dan membuka minda tentang kepentingan Bulan.','Kasih sayang, perpaduan dan semangat gotong-royong membina masyarakat yang harmoni dan sejahtera.'),
  ('Gugur Matahari','Usman Awang','Karangkraf Sdn. Bhd.',1997,97,'Puisi','Melayu','Sebuah novel yang mengisahkan tentang semangat dan ketabahan seorang individu dalam menghadapi rintangan hidup demi mencapai impian berkaitan Matahari.','Ilmu pengetahuan dan pendidikan adalah pelaburan terbaik untuk masa depan yang cemerlang.'),
  ('Gugur Langit','Arenawati','Fajar Bakti Sdn. Bhd.',1998,106,'Biografi','Melayu','Menerusi halaman demi halaman, pembaca akan dibawa menyelami cerita yang penuh intrik dan emosi yang mendalam berkaitan Langit.','Kejujuran, integriti dan amanah adalah nilai-nilai murni yang perlu diamalkan dalam kehidupan seharian.'),
  ('Gugur Laut','S. Othman Kelantan','Utusan Publications',1999,115,'Sejarah','Melayu','Karya ini merupakan satu penerokaan mendalam tentang hubungan manusia dengan alam sekitar dan nilai-nilai murni yang terkandung dalam Laut.','Menghargai warisan budaya dan sejarah adalah tanggungjawab setiap generasi untuk masa depan bangsa.'),
